INSERT INTO public.cgof_gpc_parcelamento (codigo, processo_id, proc_parcela, tipo, exercicio, valor_parcelado, valor_corrigido, parcelas, em_dia, parcelas_concluidas, providencias, obs) VALUES (6, 444, '024.00011874/2025-71', 'SEI', 2019, 22121.86, 30080.95, 48, FALSE, FALSE, 'Em 18/03/2025 foi encaminhado para Publicação em D.O. O Termo de Reconhecimento e Parcelamento de débito foi assinado pelo Secretário em 14/03/2025.', 'Processo ja foi encaminhado para a DRS para providenciar o pagamento das parcelas') ON CONFLICT (codigo) DO NOTHING;
INSERT INTO public.cgof_gpc_parcelamento (codigo, processo_id, proc_parcela, tipo, exercicio, valor_parcelado, valor_corrigido, parcelas, em_dia, parcelas_concluidas, providencias, obs) VALUES (10, 49, '024.00043986/2024-19', 'SEI', 2017, 381499.12, 539781.04, 60, FALSE, FALSE, 'O processo foi encaminhado para a DRS providenciar o termo de Reconhecimento de Parcelamento de Débito no dia 26/03/2025. o Processo retornou em 25/06/2025 e em 27/06/2025 segue para o secretario assinar o termo de reconhecimento e parcelamento de débito através da Assisttec do coordenador', 'Encontra-se na pasta DIONE TCE\PARCELAMENTOS\DRS - 1\Convênio 780/2016 - ICAVC - Exercício 2017 os arquivos Termo de Parcelamento e Comprovante de pagamento 1º Parcela SE ENCONTRA NA PASTA GPC DE PARCELAMENTO') ON CONFLICT (codigo) DO NOTHING;
INSERT INTO public.cgof_gpc_parcelamento (codigo, processo_id, proc_parcela, tipo, exercicio, valor_parcelado, valor_corrigido, parcelas, em_dia, parcelas_concluidas, providencias, obs) VALUES (11, 503, '024.00066225/2024-27', 'SEI', 2018, 141664.5, 194770.72, 60, FALSE, FALSE, 'O processo foi enviado para Assistencia tecnica do coordenador para ser enviado para DRS para se providenciar o Termo de Reconhecimento de Parcelamento de Débito', NULL) ON CONFLICT (codigo) DO NOTHING;
